    )
    .unwrap();
    let guide = (1..=260)
        .map(|line| {
            if line == 200 {
                "unique neighbor target appears in the middle of this guide\n".to_owned()
            } else {
                format!(
                    "context line {line} with filler filler filler filler filler filler filler filler filler filler\n"
                )
