fn run_pack(
    query: String,
    invocation: ResolvedInvocation,
    budget_tokens: usize,
    include_neighbors: usize,
    include_symbol_definitions: bool,
) -> Result<()> {
    if budget_tokens == 0 {
        bail!("--budget-tokens must be at least 1");
    }
    if invocation.limit == 0 {
        bail!("--limit must be at least 1");
    }
    let policy = model_policy(invocation.offline, invocation.no_download);
    let index = build_index_for_mode(
        &invocation.source,
        invocation.ref_name.as_deref(),
        invocation.mode,
        encoder_spec(invocation.encoder, invocation.model.as_deref(), policy),
        invocation.cache,
        invocation.offline,
        invocation.include_docs,
        extension_set(&invocation.extensions),
    )?;
    let options = SearchOptions::new(invocation.limit).with_mode(invocation.mode);
    let results = index.search_with(&query, &options)?;
    let mut remaining_chars = budget_tokens.saturating_mul(4);
    let mut seen_files = std::collections::HashSet::new();
    let mut seen_chunks = std::collections::HashSet::new();
    let mut packed = Vec::new();
    let mut state = PackState {
        packed: &mut packed,
        seen_chunks: &mut seen_chunks,
        remaining_chars: &mut remaining_chars,
    };
    let chunks = &index.chunks;
    let symbol_definition_chunks = if include_symbol_definitions {
        query_symbol_definition_chunks(&query, chunks)
    } else {
        Vec::new()
    };
    for result in results {
        if *state.remaining_chars == 0 || !seen_files.insert(result.chunk.file_path.clone()) {
            continue;
        }
        push_pack_chunk(
            &mut state,
            &result.chunk,
            Some(result.score),
            result.source.to_string(),
            "primary",
            format!("ranked by {} for the pack query", invocation.mode),
        );
        if let Some(header) = file_header_chunk(chunks, &result.chunk) {
            push_pack_chunk(
                &mut state,
                header,
                None,
                "file_header".to_owned(),
                "file_header",
                format!("file header context for {}", result.chunk.file_path),
            );
        }
        if include_neighbors > 0 {
            for neighbor in adjacent_chunks(chunks, &result.chunk, include_neighbors) {
                if *state.remaining_chars == 0 {
                    break;
                }
                push_pack_chunk(
                    &mut state,
                    neighbor,
                    None,
                    "adjacent".to_owned(),
                    "neighbor",
                    format!(
                        "adjacent context for {}:{}-{}",
                        result.chunk.file_path, result.chunk.start_line, result.chunk.end_line
                    ),
                );
            }
        }
        if include_symbol_definitions {
            for definition in &symbol_definition_chunks {
                if *state.remaining_chars == 0 {
                    break;
                }
                push_pack_chunk(
                    &mut state,
                    definition,
                    None,
                    "symbol".to_owned(),
                    "symbol_definition",
                    "defines a symbol named in the pack query".to_owned(),
                );
            }
        }
    }
    let payload = json!({
        "query": query,
        "source": invocation.source,
        "mode": invocation.mode.to_string(),
        "limit": invocation.limit,
        "budget_tokens": budget_tokens,
        "include_neighbors": include_neighbors,
        "include_symbol_definitions": include_symbol_definitions,
        "estimated_tokens_used": budget_tokens.saturating_mul(4).saturating_sub(remaining_chars).div_ceil(4),
        "stats": index.stats(),
        "warnings": index.warnings(),
        "items": packed,
    });
    println!("{}", serde_json::to_string_pretty(&payload)?);
    Ok(())
}

fn file_header_chunk<'a>(chunks: &'a [Chunk], chunk: &Chunk) -> Option<&'a Chunk> {
    if chunk.start_line == 1 {
        return None;
    }
    chunks
        .iter()
        .find(|candidate| candidate.file_path == chunk.file_path && candidate.start_line == 1)
}

struct PackState<'a> {
    packed: &'a mut Vec<Value>,
    seen_chunks: &'a mut std::collections::HashSet<(String, usize, usize)>,
    remaining_chars: &'a mut usize,
}

fn push_pack_chunk(
    state: &mut PackState,
    chunk: &Chunk,
    score: Option<f32>,
    source: String,
    kind: &str,
    why: String,
) {
    if *state.remaining_chars == 0
        || !state
            .seen_chunks
            .insert((chunk.file_path.clone(), chunk.start_line, chunk.end_line))
    {
        return;
    }
    let content = if chunk.content.len() > *state.remaining_chars {
        chunk
            .content
            .chars()
            .take(*state.remaining_chars)
            .collect::<String>()
    } else {
        chunk.content.clone()
    };
    *state.remaining_chars = state.remaining_chars.saturating_sub(content.len());
    state.packed.push(json!({
        "kind": kind,
        "file_path": chunk.file_path,
        "start_line": chunk.start_line,
        "end_line": chunk.end_line,
        "score": score,
        "source": source,
        "why": why,
        "symbols": chunk.symbols,
        "breadcrumbs": chunk.breadcrumbs,
        "content": content,
    }));
}

fn adjacent_chunks<'a>(
    chunks: &'a [Chunk],
    target: &Chunk,
    include_neighbors: usize,
) -> Vec<&'a Chunk> {
    let mut before: Vec<&Chunk> = chunks
        .iter()
        .filter(|chunk| {
            chunk.file_path == target.file_path
                && chunk.start_line < target.start_line
                && !(chunk.start_line == target.start_line && chunk.end_line == target.end_line)
        })
        .collect();
    before.sort_by_key(|chunk| std::cmp::Reverse(chunk.end_line));
    let mut after: Vec<&Chunk> = chunks
        .iter()
        .filter(|chunk| {
            chunk.file_path == target.file_path
                && chunk.start_line > target.start_line
                && !(chunk.start_line == target.start_line && chunk.end_line == target.end_line)
        })
        .collect();
    after.sort_by_key(|chunk| chunk.start_line);
    before
        .into_iter()
        .take(include_neighbors)
        .chain(after.into_iter().take(include_neighbors))
        .collect()
}

fn query_symbol_definition_chunks<'a>(query: &str, chunks: &'a [Chunk]) -> Vec<&'a Chunk> {
    let terms: std::collections::HashSet<String> = query
        .split(|c: char| !(c.is_ascii_alphanumeric() || c == '_' || c == '$'))
        .filter(|term| term.len() >= 3)
        .map(|term| term.to_ascii_lowercase())
        .collect();
    if terms.is_empty() {
        return Vec::new();
    }
    chunks
        .iter()
        .filter(|chunk| {
            chunk.symbols.iter().any(|symbol| {
                terms.contains(&symbol.name.to_ascii_lowercase())
                    && matches!(
                        symbol.kind.as_str(),
                        "class"
                            | "const"
                            | "def"
                            | "enum"
                            | "fn"
                            | "function"
                            | "impl"
                            | "interface"
                            | "struct"
                            | "trait"
                            | "type"
                    )
            })
        })
        .collect()
}

#[allow(clippy::too_many_arguments)]
fn resolve_invocation(
    profile_name: Option<&str>,
    source: Option<String>,
    mode: Option<ModeArg>,
    limit: Option<usize>,
    model: Option<String>,
    encoder: Option<EncoderArg>,
    offline: bool,
    no_download: bool,
    cache: CacheConfig,
    include_docs: bool,
    extensions: Vec<String>,
) -> Result<ResolvedInvocation> {
    let profile = match profile_name {
        Some(name) => Some(profiles::get_profile(&platform_cache_root()?, name)?),
        None => None,
    };
    let source = source
        .or_else(|| std::env::var("SIFS_SOURCE").ok())
        .or_else(|| profile.as_ref().and_then(|profile| profile.source.clone()))
        .unwrap_or_else(|| ".".to_owned());
    let ref_name = profile
        .as_ref()
        .and_then(|profile| profile.ref_name.clone());
    let mode = mode
        .map(SearchMode::from)
        .or_else(|| profile.as_ref().and_then(|profile| profile.mode))
        .unwrap_or(SearchMode::Hybrid);
    let limit = limit
        .or_else(|| profile.as_ref().and_then(|profile| profile.limit))
        .unwrap_or(5);
    if limit == 0 {
        bail!("--limit must be at least 1");
    }
    let model = model.or_else(|| profile.as_ref().and_then(|profile| profile.model.clone()));
    let encoder = encoder
        .or_else(|| {
            profile
                .as_ref()
                .and_then(|profile| profile.encoder.as_deref())
                .and_then(parse_encoder_name)
        })
        .unwrap_or(EncoderArg::Model2Vec);
    let offline = offline
        || profile
            .as_ref()
            .and_then(|profile| profile.offline)
            .unwrap_or(false);
    let no_download = no_download
        || profile
            .as_ref()
            .and_then(|profile| profile.no_download)
            .unwrap_or(false);
    let cache = match profile.as_ref() {
        Some(profile) if matches!(cache, CacheConfig::Platform) => {
            if profile.no_cache.unwrap_or(false) {
                CacheConfig::Disabled
            } else if profile.project_cache.unwrap_or(false) {
                CacheConfig::Project
            } else if let Some(path) = &profile.cache_dir {
                CacheConfig::Custom(path.clone())
            } else {
                cache
            }
        }
        _ => cache,
    };
    let include_docs = include_docs
        || profile
            .as_ref()
            .and_then(|profile| profile.include_docs)
            .unwrap_or(false);
    let extensions = if extensions.is_empty() {
        profile
            .as_ref()
            .and_then(|profile| profile.extensions.clone())
            .unwrap_or_default()
    } else {
        extensions
    };
    Ok(ResolvedInvocation {
        source,
        ref_name,
        mode,
        limit,
        model,
        encoder,
        offline,
        no_download,
        cache,
        include_docs,
        extensions,
    })
}

fn parse_encoder_name(value: &str) -> Option<EncoderArg> {
    match value {
        "model2vec" => Some(EncoderArg::Model2Vec),
        "hashing" => Some(EncoderArg::Hashing),
        _ => None,
    }
}

fn run_search(command: SearchCommand) -> Result<()> {
    if let Some(result) = try_daemon_search(&command)? {
        print_search_output(
            &result.query,
            &result.source.source,
            &SearchOptions {
                top_k: command.limit,
                mode: result.mode,
                alpha: None,
                filter_languages: command.languages.clone(),
                filter_paths: command.filter_paths.clone(),
                use_query_cache: true,
                explain: command.explain,
            },
            result.stats,
            u128::from(result.elapsed_ms),
            &daemon_warnings(&result.warnings),
            &result.results,
            command.context_lines,
            command.explain,
            &command.output,
        )?;
        return Ok(());
    }

    let policy = model_policy(command.offline, command.no_download);
    let started = Instant::now();
    let index = build_index_for_mode(
        &command.source,
        command.ref_name.as_deref(),
        command.mode,
        encoder_spec(command.encoder, command.model.as_deref(), policy),
        command.cache,
        command.offline,
        command.include_docs,
        extension_set(&command.extensions),
    )?;
    let warnings = search_warnings(&index, &command.filter_paths, &command.languages)
        .into_iter()
        .chain(context_warnings(&command.source, command.context_lines))
        .collect::<Vec<_>>();
    let mut options = SearchOptions::new(command.limit).with_mode(command.mode);
    options.filter_languages = command.languages;
    options.filter_paths = command.filter_paths;
    options.explain = command.explain;
    let results = index.search_with(&command.query, &options)?;
    let elapsed_ms = started.elapsed().as_millis();

    print_search_output(
        &command.query,
        &command.source,
        &options,
        index.stats(),
        elapsed_ms,
        &warnings,
        &results,
        command.context_lines,
        command.explain,
        &command.output,
    )
}

#[allow(clippy::too_many_arguments)]
fn print_search_output(
    query: &str,
    source: &str,
    options: &SearchOptions,
    stats: IndexStats,
    elapsed_ms: u128,
    warnings: &[String],
    results: &[SearchResult],
    context_lines: usize,
    explain: bool,
    output: &OutputArgs,
) -> Result<()> {
    let payload = search_payload(
        query,
        source,
        options,
        stats,
        elapsed_ms,
        warnings,
        results,
        context_lines,
    );
    if output.json {
        println!("{}", serde_json::to_string_pretty(&payload)?);
    } else if output.jsonl {
        for result in results {
            println!(
                "{}",
                serde_json::to_string(&search_result_record(
                    query,
                    source,
                    options,
                    elapsed_ms,
                    warnings,
                    result,
                    context_lines,
                ))?
            );
        }
    } else {
        if explain {
            print_explanation(query, source, options, elapsed_ms, warnings);
        }
        match output.format {
            TextFormat::Human => {
                if results.is_empty() {
                    println!("No results found.");
                } else {
                    println!(
                        "{}",
                        format_results(
                            &format!("Search results for: {:?} (mode={})", query, options.mode),
                            results,
                        )
                    );
                }
            }
            TextFormat::Compact => print_compact_results(results),
        }
    }
    Ok(())
}

fn try_daemon_search(
    command: &SearchCommand,
) -> Result<Option<sifs::daemon::protocol::SearchResultSet>> {
    let Some(client) = daemon_client_if_running()? else {
        return Ok(None);
    };
    let source = SourceSpec::resolve(&command.source, command.ref_name.clone(), command.offline)?;
    let policy = model_policy(command.offline, command.no_download);
    let runtime_options = with_index_filters(
        match command.mode {
            SearchMode::Bm25 => IndexRuntimeOptions::sparse(command.cache.clone()),
            SearchMode::Semantic | SearchMode::Hybrid => IndexRuntimeOptions::with_encoder(
                encoder_spec(command.encoder, command.model.as_deref(), policy),
                command.cache.clone(),
            ),
        },
        command.include_docs,
        &command.extensions,
    );
    let mut search = SearchOptions::new(command.limit).with_mode(command.mode);
    search.filter_languages = command.languages.clone();
    search.filter_paths = command.filter_paths.clone();
    match client.send(DaemonRequest::Search {
        source,
        options: runtime_options,
        query: command.query.clone(),
        search: SearchOptionsWire::from(search),
    }) {
        Ok(DaemonResult::Search(results)) => Ok(Some(results)),
        Ok(other) => bail!("unexpected daemon response: {other:?}"),
        Err(_) => Ok(None),
    }
}

fn with_index_filters(
    mut options: IndexRuntimeOptions,
    include_docs: bool,
    extensions: &[String],
) -> IndexRuntimeOptions {
    options.include_text_files = include_docs;
    options.extensions = normalized_extensions(extensions);
    options
}

fn normalized_extensions(values: &[String]) -> Option<Vec<String>> {
    if values.is_empty() {
        return None;
    }
    let mut values = values
        .iter()
        .filter_map(|value| {
            let value = value.trim().trim_start_matches('.').to_lowercase();
            (!value.is_empty()).then(|| format!(".{value}"))
        })
        .collect::<Vec<_>>();
    values.sort();
    values.dedup();
    (!values.is_empty()).then_some(values)
}

